// 切换到测试排版规则说明文档并读取内容
var targetDoc = null;
for (var i = 0; i < Application.Documents.Count; i++) {
    var doc = Application.Documents.Item(i + 1);
    if (doc.Name.indexOf("测试排版规则说明") !== -1) {
        targetDoc = doc;
        break;
    }
}

if (!targetDoc) {
    return { error: "未找到测试排版规则说明.docx 文档" };
}

var content = [];
for (var i = 1; i <= targetDoc.Paragraphs.Count; i++) {
    var para = targetDoc.Paragraphs.Item(i);
    content.push(para.Range.Text.replace(/\r\n$/, ''));
}

return { success: true, paragraphs: content };

